import{_ as e,o as t,c as a,Q as r}from"./chunks/framework.b67c47e6.js";const f=JSON.parse('{"title":"Logistics","description":"","frontmatter":{},"headers":[],"relativePath":"guide/logistics/index.md","filePath":"guide/logistics/index.md","lastUpdated":1773939149000}'),i={name:"guide/logistics/index.md"},o=r('<h1 id="logistics" tabindex="-1">Logistics <a class="header-anchor" href="#logistics" aria-label="Permalink to &quot;Logistics&quot;">​</a></h1><p>The Logistics view provides an overview of material requirements across your constructibles, helping you track which parts are available and which still need to be prepared.</p><nav class="table-of-contents"><ul><li><a href="#layout">Layout</a></li><li><a href="#material-tracking">Material Tracking</a></li><li><a href="#filtering">Filtering</a></li><li><a href="#marking-parts-ready">Marking Parts Ready</a></li><li><a href="#connection-to-other-features">Connection to Other Features</a></li></ul></nav><h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><p>The logistics interface has three panels:</p><ul><li><strong>Left panel</strong> — Branch selection (plates or profiles) and size filters.</li><li><strong>Center panel</strong> — Material inventory table grouped by zone.</li><li><strong>Right panel</strong> — Detailed information for the selected item.</li></ul><h2 id="material-tracking" tabindex="-1">Material Tracking <a class="header-anchor" href="#material-tracking" aria-label="Permalink to &quot;Material Tracking&quot;">​</a></h2><p>The table shows each material part needed for production, organized by:</p><table><thead><tr><th>Column</th><th>Description</th></tr></thead><tbody><tr><td><strong>Zone</strong></td><td>The structural area in the design where this part is used.</td></tr><tr><td><strong>Reference</strong></td><td>Material identification code.</td></tr><tr><td><strong>Total count</strong></td><td>Total number of this part needed across all constructibles.</td></tr><tr><td><strong>Per constructible</strong></td><td>Breakdown showing how many are needed for each assembly/module.</td></tr><tr><td><strong>Dimensions</strong></td><td>Width × Length (for plates) or profile dimensions.</td></tr><tr><td><strong>Ready parts</strong></td><td>How many have been prepared and are available.</td></tr></tbody></table><h2 id="filtering" tabindex="-1">Filtering <a class="header-anchor" href="#filtering" aria-label="Permalink to &quot;Filtering&quot;">​</a></h2><ul><li><strong>Branch</strong> — Switch between viewing plate materials or profile materials.</li><li><strong>Size</strong> — Filter to a specific material size (dimensional variant).</li></ul><h2 id="marking-parts-ready" tabindex="-1">Marking Parts Ready <a class="header-anchor" href="#marking-parts-ready" aria-label="Permalink to &quot;Marking Parts Ready&quot;">​</a></h2><p>You can update the &quot;ready parts&quot; count for each material to track preparation progress:</p><ul><li>Click on a cell to edit the ready count.</li><li>Use the <strong>All parts ready</strong> button to quickly mark all parts as available.</li></ul><h2 id="connection-to-other-features" tabindex="-1">Connection to Other Features <a class="header-anchor" href="#connection-to-other-features" aria-label="Permalink to &quot;Connection to Other Features&quot;">​</a></h2><ul><li>Material requirements are derived from the designs and their BoM data.</li><li>The <a href="/guide/logistics/delivery/">Delivery &amp; Racks</a> feature uses the logistics data to plan how completed assemblies are loaded for transport.</li><li><a href="/guide/reports/">Reports</a> can generate Bills of Materials for ordering the materials tracked here.</li></ul>',16),n=[o];function l(s,d,c,h,g,u){return t(),a("div",null,n)}const m=e(i,[["render",l]]);export{f as __pageData,m as default};
